const https = require('https');

function buildQs(params) {
  return Object.entries(params)
    .map(([k, v]) => encodeURIComponent(k) + '=' + encodeURIComponent(String(v)))
    .join('&');
}

async function sbGet(table, params) {
  return new Promise((resolve, reject) => {
    const qs = buildQs(params);
    const path = '/rest/v1/' + table + '?' + qs;
    const opts = {
      hostname: 'srhpmvfdzllsovluahjf.supabase.co',
      port: 443,
      path: path,
      method: 'GET',
      headers: {
        'apikey': API_KEY,
        'Authorization': AUTH
      }
    };
    const req = https.request(opts, (res) => {
      let body = '';
      res.on('data', c => body += c);
      res.on('end', () => {
        try { resolve(JSON.parse(body)); }
        catch { resolve([]); }
      });
    });
    req.on('error', () => resolve([]));
    req.end();
  });
}


const now = new Date();

function getDayWindow(days) {
  const target = new Date(now.getTime() - days * 24 * 60 * 60 * 1000);
  const from = new Date(target.getTime() - 30 * 60 * 1000);
  const to = new Date(target.getTime() + 30 * 60 * 1000);
  return { from: from.toISOString(), to: to.toISOString(), label: 'day' + days };
}

const windows = [getDayWindow(3), getDayWindow(7), getDayWindow(14)];
const due = [];

for (const window of windows) {
  const deliveries = await sbGet('bs_event_log', {
    action_type: 'eq.bs_compliance_email_sent',
    created_at: 'gte.' + window.from,
    'created_at.lte': window.to,
    select: 'task_id,created_at,payload'
  });

  for (const delivery of (Array.isArray(deliveries) ? deliveries : [])) {
    const nurtureType = 'bs_nurture_' + window.label;
    const existing = await sbGet('bs_event_log', {
      action_type: 'eq.' + nurtureType,
      task_id: 'eq.' + delivery.task_id,
      select: 'id',
      limit: '1'
    });

    if (!existing || !Array.isArray(existing) || existing.length === 0) {
      let payload = {};
      try { payload = JSON.parse(delivery.payload); } catch(e) {}
      due.push({
        call_sid: delivery.task_id,
        to_email: payload.to || '',
        touch: window.label,
        nurture_type: nurtureType,
        delivered_at: delivery.created_at
      });
    }
  }
}

return due.map(d => ({ json: d }));

